// ── Claude API ─────────────────────────────────────────────────
async function callJSON(sys, user) {
  const r = await fetch(API,{method:"POST",headers:{"Content-Type":"application/json"},
    body:JSON.stringify({model:MODEL,max_tokens:1000,
      system:sys+"\nReturn ONLY valid JSON. No markdown.",
      messages:[{role:"user",content:user}]})});
  const d = await r.json();
  const t = d.content?.[0]?.text||"";
  try { return JSON.parse(t.replace(/```json|```/g,"").trim()); } catch { return null; }
}

const SYS_POPO   = `You are POPO, Hermes OS production director (a crab who runs an AI pixel art company). Return JSON: {"directive":"...","assignedAgent":"ARTIST","taskSpec":{"name":"...","type":"character|item|tile|icon","theme":"...","palette":["#hex"],"description":"..."},"message":"..."}`;
const SYS_ARTIST = `You are Hermes Pixel Artist AI. Return JSON: {"assetName":"...","type":"character|item|tile|icon","palette":["#hex1","#hex2","#hex3","#hex4","#hex5"],"description":"...","layers":["background","base","details","outline"],"animationFrames":1,"tags":["..."]}`;
const SYS_QC     = `You are Hermes QC Agent. Return JSON: {"passed":true,"score":85,"checks":{"paletteConsistency":{"pass":true,"note":"..."},"outlineQuality":{"pass":true,"note":"..."},"readability":{"pass":true,"note":"..."},"styleCoherence":{"pass":true,"note":"..."}},"feedback":"...","approved":true}`;

function genPixels(pal, type) {
  const bg=pal[0]||"#1a1a2e", cols=pal.slice(1);
  const g=Array.from({length:16},()=>Array(16).fill(bg));
  const c=(x,y,i=0)=>{if(x>=0&&x<16&&y>=0&&y<16)g[y][x]=cols[i%cols.length];};
  if(type==="character"){
    for(let x=5;x<=10;x++){c(x,2,0);c(x,3,0);c(x,4,0);}
    g[3][6]="#f0f0f0";g[3][9]="#f0f0f0";
    for(let y=5;y<=9;y++)for(let x=4;x<=11;x++)c(x,y,1);
    for(let y=5;y<=8;y++){c(3,y,2);c(12,y,2);}
    for(let y=10;y<=14;y++){c(5,y,2);c(6,y,2);c(9,y,2);c(10,y,2);}
  } else if(type==="item"){
    const cx=8,cy=8,r=5;
    for(let y=0;y<16;y++)for(let x=0;x<16;x++){
      const d=Math.sqrt((x-cx)**2+(y-cy)**2);
      if(d<r)c(x,y,d<r*.4?0:d<r*.7?1:2);
    }
    c(6,5,0);c(7,5,0);
  } else if(type==="tile"){
    for(let y=0;y<16;y++)for(let x=0;x<16;x++)if((x+y)%4<2)c(x,y,(x+y)%4);
    for(let x=0;x<16;x++){c(x,0,3);c(x,15,3);}
    for(let y=0;y<16;y++){c(0,y,3);c(15,y,3);}
  } else {
    const cx=8,cy=8;
    for(let i=0;i<12;i++){
      const a=i*(Math.PI*2/12),r=i%2===0?6:3;
      c(Math.round(cx+r*Math.cos(a)),Math.round(cy+r*Math.sin(a)),i%2===0?0:1);
    }
    c(8,8,0);
  }
  return g;
}

