export default function HermesOS() {
  const router = useRouter();

  // ── AUTH GATE ──
  useEffect(() => {
    try {
      const raw = localStorage.getItem("kaf_auth");
      if (!raw) { router.replace("/login"); return; }
      const d = JSON.parse(raw);
      if (!d.user || !d.ts || Date.now() - d.ts > 7 * 24 * 60 * 60 * 1000) {
        router.replace("/login");
      }
    } catch { router.replace("/login"); }
  }, []);

  const [agSt,  setAgSt]  = useState({popo:"idle",scout:"idle",artist:"idle",webgen:"idle",qc:"idle",pkg:"idle"});
  const [agPr,  setAgPr]  = useState({popo:0,scout:0,artist:0,webgen:0,qc:0,pkg:0});
  const [gLogs, setGLogs] = useState([]);
  const [rLogs, setRLogs] = useState({popo:[],scout:[],artist:[],webgen:[],qc:[],pkg:[]});
  const [tasks, setTasks] = useState({popo:[],scout:[],artist:[],webgen:[],qc:[],pkg:[]});
  const [asset,   setAsset]   = useState(null);
  const [qcRep,   setQcRep]   = useState(null);
  const [dlReady, setDlReady] = useState(false);
  const [webPreview, setWebPreview] = useState<string|null>(null);
  const [running, setRunning] = useState(false);
  const [selRoom, setSelRoom] = useState(null);
  const [prompt,  setPrompt]  = useState("a fantasy RPG warrior character");
  const [prodCnt, setProdCnt] = useState(0);
  const [flow,    setFlow]    = useState("");
  const [clock,      setClock]      = useState(new Date());
  const [isLive,     setIsLive]     = useState(false);
  const [personaAgent, setPersonaAgent] = useState<string|null>(null);
  const [sidebarTab,   setSidebarTab]   = useState<string>("status");
  const [gwStatus,     setGwStatus]     = useState<boolean|null>(null);
  const [chatMessages, setChatMessages] = useState<Record<string,Array<{role:string,text:string,ts:string}>>>({popo:[],scout:[],artist:[],webgen:[],qc:[],pkg:[]});
  const [personas,     setPersonas]     = useState<Record<string,any>>({});
  const [chatInput,    setChatInput]    = useState<string>("");
  const [chatSending,  setChatSending]  = useState<boolean>(false);

  // ── Navigate when dojo/library rooms clicked ──
  useEffect(() => {
    if (selRoom === "dojo") { setSelRoom(null); router.push("/dojo"); }
    if (selRoom === "library") { setSelRoom(null); router.push("/library"); }
  }, [selRoom]);

  // ── Clock tick ──
  useEffect(()=>{const t=setInterval(()=>setClock(new Date()),1000);return()=>clearInterval(t);},[]);

  // ── Real Kanban polling (every 5s) ──
  useEffect(() => {
    const poll = async () => {
      try {
        const res = await fetch('/api/kanban/status');
        const data = await res.json();
        if (data?.agents) {
          const newSt: any = {};
          const newPr: any = {};
          const newTasks: any = { popo:[], scout:[], artist:[], webgen:[], qc:[], pkg:[] };
          let hasActivity = false;

          for (const [id, agent] of Object.entries(data.agents) as any) {
            if (id && agent) {
              newSt[id] = agent.status || 'idle';
              newPr[id] = agent.progress || 0;
              newTasks[id] = (agent.tasks || []).map((t: any) => ({
                name: t.name, status: t.status, desc: t.name, progress: t.progress
              }));
              if (agent.status !== 'idle') hasActivity = true;
            }
          }

          setAgSt(p => ({...p, ...newSt}));
          setAgPr(p => ({...p, ...newPr}));
          setTasks(p => ({...p, ...newTasks}));

          if (data.pipeline) setFlow(data.pipeline);
          if (data.totalCount > 0) {
            setIsLive(true);
            setProdCnt(data.doneCount || 0);
          }
          if (!hasActivity && data.pipeline) setFlow("");
        }
      } catch {}
    };

    // Also fetch forge stats
    const pollStats = async () => {
      try {
        const res = await fetch('/api/forge/stats');
        const data = await res.json();
        if (data?.totalProductions > 0) {
          setProdCnt(data.totalProductions);
        }
      } catch {}
    };

    poll(); pollStats();
    const interval = setInterval(() => { poll(); pollStats(); }, 5000);
    return () => clearInterval(interval);
  }, []);

  // ── Gateway health polling (every 30s) ──
  useEffect(() => {
    const check = async () => {
      try {
        const res = await fetch('/api/health');
        const data = await res.json();
        setGwStatus(data.status === 'online');
      } catch { setGwStatus(false); }
    };
    check();
    const i = setInterval(check, 30000);
    return () => clearInterval(i);
  }, []);

  // ── Load agent personas ──
  useEffect(() => {
    const load = async () => {
      try {
        const res = await fetch('/api/persona');
        const data = await res.json();
        setPersonas(data);
      } catch {}
    };
    load();
  }, []);

  const log = useCallback((message,type="info",agent=null)=>{
    const time = new Date().toLocaleTimeString("en-US",{hour12:false});
    const e = {message,type,time,agent};
    setGLogs(p=>[...p.slice(-120),e]);
    if(agent){const key=AGENT_MAP[agent];if(key)setRLogs(p=>({...p,[key]:[...p[key].slice(-30),e]}));}
  },[]);

  const setSt = useCallback((ag,st,pr)=>{setAgSt(p=>({...p,[ag]:st}));setAgPr(p=>({...p,[ag]:pr}));},[]);
  const addTask = useCallback((ag,task)=>setTasks(p=>({...p,[ag]:[...p[ag],{...task,id:Date.now()}]})),[]);
  const updTask = useCallback((ag,name,upd)=>setTasks(p=>({...p,[ag]:p[ag].map(t=>t.name===name?{...t,...upd}:t)})),[]);

  const reset = useCallback(()=>{
    setAgSt({popo:"idle",scout:"idle",artist:"idle",webgen:"idle",qc:"idle",pkg:"idle"});
    setAgPr({popo:0,scout:0,artist:0,webgen:0,qc:0,pkg:0});
    setTasks({popo:[],scout:[],artist:[],webgen:[],qc:[],pkg:[]});
    setRLogs({popo:[],scout:[],artist:[],webgen:[],qc:[],pkg:[]});
    setAsset(null);setQcRep(null);setDlReady(false);setWebPreview(null);
  },[]);

  // ── Real Kanban Pipeline Execution ──
  const run = useCallback(async(userPrompt: string) => {
    if(running) return;
    setRunning(true); setFlow("POPO → ARTIST → QC → PKG");
    log("══════════════════════════════════","system");
    log("✦ POPO INITIATING · " + userPrompt,"system","POPO");

    // Try real pipeline first
    try {
      const res = await fetch('/api/forge/execute', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ theme: userPrompt })
      });
      const data = await res.json();

      if (data.success) {
        log("✦ SWARM DEPLOYED — agents collaborating freely","success","POPO");
        log("Theme: " + data.theme,"info","POPO");
        log("Workers: " + (data.swarm?.workers?.length || 0) + " in parallel","info","POPO");
        log("Agents can discuss freely via task comments","system","POPO");
        setFlow(data.message || "🐝 SWARM ACTIVE");
        setIsLive(true);
        setTimeout(() => {
          setRunning(false);
          log("Pipeline handed off to Kanban agents","success","POPO");
        }, 3000);
        return;
      }
      throw new Error(data.error || "Pipeline creation failed");
    } catch (err: any) {
      log("Kanban unavailable: " + err.message,"warn","POPO");
      log("Generating asset directly...","warn","POPO");
    }

    // Generate asset directly (real file, not fake animation)
    setFlow("✦ GENERATING ASSET");
    try {
      setSt("popo","active",20); setSelRoom("popo");
      addTask("popo",{name:"Analyze Request",status:"running",desc:userPrompt,progress:30});
      log("Analyzing request: " + userPrompt,"info","POPO");
      await sleep(400);
      updTask("popo","Analyze Request",{status:"done",progress:100});

      // Call the generate API — creates a REAL PNG file
      setSt("artist","working",30); setSelRoom("artist");
      addTask("artist",{name:"Generate Sprite",status:"running",desc:userPrompt,progress:20});
      log("Generating pixel art sprite...","info","ARTIST");

      const genRes = await fetch('/api/forge/generate', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ theme: userPrompt, type: 'character' })
      });
      const genData = await genRes.json();

      if (genData.success) {
        updTask("artist","Generate Sprite",{status:"done",progress:100});
        setSt("artist","idle",100);
        setAsset(genData.asset);
        log(`✓ Asset generated: ${genData.asset.name}.png`,"success","ARTIST");
        log(`Palette: ${genData.asset.palette.join(' · ')}`,"info","ARTIST");
      } else {
        throw new Error(genData.error || "Generation failed");
      }

      // Web Generator — runs in parallel with Pixel Studio
      setSt("webgen","working",30); setSelRoom("webgen");
      addTask("webgen",{name:"Generate Web Page",status:"running",desc:userPrompt,progress:20});
      log("Generating web landing page...","info","WEBGEN");

      const webRes = await fetch('/api/forge/generate-web', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ theme: userPrompt, feature: 'landing-page' })
      });
      const webData = await webRes.json();

      if (webData.success) {
        updTask("webgen","Generate Web Page",{status:"done",progress:100});
        setSt("webgen","idle",100);
        setWebPreview(webData.asset.previewUrl);
        log(`✓ Web page ready: ${webData.asset.name}`,"success","WEBGEN");
      } else {
        log("Web generation skipped: " + (webData.error || "unknown"),"warn","WEBGEN");
        setSt("webgen","idle",100);
      }

      // QC
      setSt("qc","reviewing",20); setSelRoom("qc");
      addTask("qc",{name:"Validate Asset",status:"reviewing",progress:30});
      log("Running QC validation...","info","QC");
      await sleep(500);
      updTask("qc","Validate Asset",{status:"done",progress:100});
      setQcRep({approved:true,score:8,checks:{paletteConsistency:{pass:true,note:"Clean palette"},outlineQuality:{pass:true,note:"Crisp outlines"},readability:{pass:true,note:"Clear at 16x16"},styleCoherence:{pass:true,note:"Consistent"}},feedback:"Approved — good quality pixel art"});
      setSt("qc","idle",100);
      log("✓ QC PASSED — 8/10","success","QC");

      // Package
      setSt("pkg","packaging",20); setSelRoom("pkg");
      addTask("pkg",{name:"Package Asset",status:"running",progress:30});
      log("Packaging asset...","info","PKG");
      await sleep(600);
      updTask("pkg","Package Asset",{status:"done",progress:100});
      setSt("pkg","idle",100);
      setDlReady(true);
      setProdCnt(p=>p+1);

      // Feed XP via dojo API
      try {
        await fetch('/api/dojo/agents', {
          method: 'POST',
          headers: {'Content-Type':'application/json'},
          body: JSON.stringify({agentId:'popo',xp:20,action:`Pipeline: ${userPrompt}`})
        });
        await fetch('/api/dojo/agents', {
          method: 'POST',
          headers: {'Content-Type':'application/json'},
          body: JSON.stringify({agentId:'artist',xp:25,action:`Sprite generation: ${userPrompt}`})
        });
      } catch {}

      log("══════════════════════════════════","system");
      log(`✦ PRODUCTION COMPLETE · ${genData.asset.name}.png`,"success","POPO");
      setFlow("");
    } catch(err: any) {
      log("GENERATION ERROR: " + err.message,"error","POPO");
      setSt("popo","failed",0); setFlow("FAILED");
    } finally { setRunning(false); }
  },[running,log,setSt,addTask,updTask,reset]);

  // ── Agent Chat Handler ──
  const sendChat = useCallback(async (agentId: string) => {
    if (!chatInput.trim() || chatSending) return;
    const msg = chatInput.trim();
    setChatInput("");
    setChatSending(true);

    // Add user message
    const ts = new Date().toLocaleTimeString("en-US",{hour12:false});
    setChatMessages(p => ({...p, [agentId]: [...p[agentId], {role:"user", text:msg, ts}]}));

    try {
      const res = await fetch('/api/agent/chat', {
        method: 'POST',
        headers: {'Content-Type':'application/json'},
        body: JSON.stringify({agentId, message: msg})
      });
      const data = await res.json();
      const response = data.response || "(no response)";
      const ts2 = new Date().toLocaleTimeString("en-US",{hour12:false});
      setChatMessages(p => ({...p, [agentId]: [...p[agentId], {role:"agent", text:response, ts:ts2}]}));
    } catch {
      const ts2 = new Date().toLocaleTimeString("en-US",{hour12:false});
      setChatMessages(p => ({...p, [agentId]: [...p[agentId], {role:"agent", text:"⚠ COMMS DOWN — try again", ts:ts2}]}));
    } finally {
      setChatSending(false);
    }
  }, [chatInput, chatSending]);

  // ── Persona Save Handler ──
  const savePersona = useCallback(async (agentId: string, persona: any) => {
    try {
      await fetch('/api/persona', {
        method: 'POST',
        headers: {'Content-Type':'application/json'},
        body: JSON.stringify({agentId, persona})
      });
      setPersonas(p => ({...p, [agentId]: persona}));
      log(`✦ ${AGENT_CFG[agentId].name} soul updated`,"success",agentId.toUpperCase());
    } catch {
      log("Failed to save persona","error");
    }
    setPersonaAgent(null);
  }, [log]);

  const download = useCallback(()=>{
    if(!asset)return;
    const pack={hermesOS:"v5.0",division:"Pixel Factory",timestamp:new Date().toISOString(),
      asset:{...asset,pixels:undefined,dimensions:"16x16"},pixelData:asset.pixels,qcReport:qcRep,
      pipeline:"POPO→ARTIST→QC→PKG",popo:"Crab Director AI",
      modelRouting:{planning:"claude-sonnet-4-6",vision:"gpt-4o",building:"deepseek-v4-pro"}};
    const blob=new Blob([JSON.stringify(pack,null,2)],{type:"application/json"});
    const url=URL.createObjectURL(blob);
    const a=document.createElement("a");
    a.href=url;a.download=`hermes-${asset.name?.replace(/\s+/g,"_")}.json`;
    a.click();URL.revokeObjectURL(url);
    log(`▼ Downloaded: hermes-${asset.name}.json`,"success");
  },[asset,qcRep,log]);

  const selCfg = selRoom ? AGENT_CFG[selRoom] : null;

  return (
    <div style={{height:"100vh",background:"#0d0f14",color:"#e2e8f0",overflow:"hidden",display:"flex",flexDirection:"column"}}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=VT323&display=swap');
        *{box-sizing:border-box;margin:0;padding:0;}
        ::-webkit-scrollbar{width:4px;} ::-webkit-scrollbar-track{background:#0d0f14;}
        ::-webkit-scrollbar-thumb{background:#252938;}
        @keyframes blink{0%,100%{opacity:1;}50%{opacity:0;}}
        @keyframes glowPulse{0%,100%{opacity:0.4;}50%{opacity:1;}}
        @keyframes slideIn{from{transform:translateX(20px);opacity:0;}to{transform:translateX(0);opacity:1;}}
        button{cursor:pointer;} button:hover{opacity:0.82;}
      `}</style>

      {/* TOP BAR */}
      <div style={{borderBottom:"1px solid #252938",padding:"7px 16px",
        display:"flex",alignItems:"center",justifyContent:"space-between",
        background:"linear-gradient(90deg,#191d28,#12151d)",
        flexShrink:0,fontFamily:"'VT323',monospace",gap:10}}>
        <div style={{display:"flex",alignItems:"center",gap:10}}>
          {/* Mini POPO in header */}
          <PopoSprite anim="idle" displaySize={32} statusColor="#f5a623" isWorking={agSt.popo!=="idle"}/>
          <span style={{color:"#f5a623",fontSize:26,letterSpacing:5}}>HERMES</span>
          <span style={{color:"#475569",fontSize:18,letterSpacing:2}}>OS</span>
          <div style={{background:"rgba(245,166,35,0.1)",border:"1px solid #8c5c0e",
            color:"#f5a623",fontSize:11,padding:"1px 7px",letterSpacing:2}}>PIXEL FACTORY</div>
        </div>

        <div style={{display:"flex",alignItems:"center",gap:8,flex:1,justifyContent:"center"}}>
          {Object.entries(AGENT_CFG).filter(([id])=>id!=="dojo"&&id!=="library").map(([id,cfg])=>{
            const st=agSt[id],on=st!=="idle";
            return (
              <div key={id} onClick={()=>setSelRoom(selRoom===id?null:id)} style={{
                display:"flex",alignItems:"center",gap:5,
                background:selRoom===id?`${cfg.color}20`:"#191d28",
                border:`1px solid ${selRoom===id?cfg.color:on?cfg.color+"55":"#252938"}`,
                padding:"3px 10px",cursor:"pointer",transition:"all 0.15s",
              }}>
                <Dot status={st}/>
                <span style={{color:on?cfg.color:"#475569",fontSize:12,letterSpacing:1}}>
                  {id==="popo"?"✦ ":""}{id.toUpperCase()}
                </span>
                {on && <span style={{color:STATUS_C[st],fontSize:10}}>{st.toUpperCase()}</span>}
              </div>
            );
          })}
          {/* Dojo & Library quick nav */}
          <div onClick={()=>router.push("/dojo")} style={{display:"flex",alignItems:"center",gap:5,background:"#191d28",border:"1px solid #c084fc33",padding:"3px 10px",cursor:"pointer",transition:"all 0.15s"}} onMouseEnter={(e)=>{e.currentTarget.style.borderColor="#c084fc";e.currentTarget.style.background="#c084fc15"}} onMouseLeave={(e)=>{e.currentTarget.style.borderColor="#c084fc33";e.currentTarget.style.background="#191d28"}}><span style={{fontSize:14}}>🏯</span><span style={{color:"#c084fc",fontSize:12,letterSpacing:1}}>DOJO</span></div>
          <div onClick={()=>router.push("/library")} style={{display:"flex",alignItems:"center",gap:5,background:"#191d28",border:"1px solid #60a5fa33",padding:"3px 10px",cursor:"pointer",transition:"all 0.15s"}} onMouseEnter={(e)=>{e.currentTarget.style.borderColor="#60a5fa";e.currentTarget.style.background="#60a5fa15"}} onMouseLeave={(e)=>{e.currentTarget.style.borderColor="#60a5fa33";e.currentTarget.style.background="#191d28"}}><span style={{fontSize:14}}>📦</span><span style={{color:"#60a5fa",fontSize:12,letterSpacing:1}}>LIBRARY</span></div>
        </div>

        <div style={{display:"flex",alignItems:"center",gap:10}}>
          {flow && <div style={{color:"#f5a623",fontSize:12,animation:"glowPulse 1.5s infinite",
            display:"flex",alignItems:"center",gap:5}}>
            <div style={{width:5,height:5,background:"#4ade80",animation:"blink 0.5s step-end infinite"}}/>
            {flow}
          </div>}
          {[{l:"🧠",m:"sonnet-4-6",c:"#f5a623"},{l:"👁",m:"gpt-4o",c:"#22d3ee"},{l:"🔨",m:"deepseek",c:"#c084fc"}].map((b,i)=>(
            <div key={i} style={{display:"flex",gap:4,alignItems:"center",
              background:"#191d28",border:"1px solid #252938",padding:"2px 7px",fontSize:11,fontFamily:"'VT323',monospace"}}>
              <span>{b.l}</span><span style={{color:b.c}}>{b.m}</span>
            </div>
          ))}
          <div style={{display:"flex",alignItems:"center",gap:5,
            background:"#191d28",border:"1px solid #252938",padding:"2px 8px"}}>
            <div style={{width:7,height:7,background:gwStatus===null?"#475569":gwStatus?"#4ade80":"#f87171",animation:gwStatus===true?"blink 2s step-end infinite":"none"}}/>
            <span style={{color:gwStatus===null?"#475569":gwStatus?"#4ade80":"#f87171",fontSize:10,fontFamily:"'VT323',monospace",letterSpacing:1}}>
              {gwStatus===null?"SCANNING":gwStatus?"GW ONLINE":"GW OFFLINE"}
            </span>
          </div>
          <div style={{textAlign:"right",fontFamily:"'VT323',monospace"}}>
            <div style={{color:"#22d3ee",fontSize:13}}>{clock.toLocaleTimeString("en-US",{hour12:false})}</div>
            <div style={{color:"#475569",fontSize:10}}>#{prodCnt.toString().padStart(4,"0")}</div>
          </div>
        </div>
      </div>

      {/* COMMAND BAR */}
      <div style={{padding:"7px 14px",borderBottom:"1px solid #252938",background:"#12151d",
        flexShrink:0,display:"flex",gap:8,alignItems:"center",flexWrap:"wrap",fontFamily:"'VT323',monospace"}}>
        <span style={{color:"#f5a623",fontSize:13,whiteSpace:"nowrap"}}>✦ POPO:</span>
        <input value={prompt} onChange={e=>setPrompt(e.target.value)}
          onKeyDown={e=>e.key==="Enter"&&!running&&run(prompt)}
          style={{flex:1,minWidth:180,background:"#050709",border:"1px solid #252938",
            color:"#e2e8f0",padding:"6px 11px",fontFamily:"'VT323',monospace",fontSize:15,outline:"none"}}/>
        <button onClick={()=>run(prompt)} disabled={running} style={{
          background:running?"#191d28":"rgba(245,166,35,0.1)",
          border:`1px solid ${running?"#252938":"#f5a623"}`,
          color:running?"#475569":"#f5a623",
          padding:"6px 16px",fontFamily:"'VT323',monospace",fontSize:15,letterSpacing:2,minWidth:130,opacity:running?0.6:1}}>
          {running?"▮▮ RUNNING...":"▶ PRODUCE"}
        </button>
        {dlReady && <button onClick={download} style={{
          background:"rgba(74,222,128,0.1)",border:"1px solid #4ade80",color:"#4ade80",
          padding:"6px 14px",fontFamily:"'VT323',monospace",fontSize:15,letterSpacing:2}}>▼ DOWNLOAD</button>}
        <div style={{display:"flex",gap:4,flexWrap:"wrap"}}>
          {QUICK.map((q,i)=>(
            <button key={i} onClick={()=>setPrompt(q)} style={{
              background:"none",border:"1px solid #252938",color:"#475569",
              padding:"2px 7px",fontFamily:"'VT323',monospace",fontSize:11}}>{q}</button>
          ))}
        </div>
      </div>

      {/* MAIN */}
      <div style={{flex:1,display:"flex",overflow:"hidden",minHeight:0}}>
        <div style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden",minWidth:0}}>
          <div style={{flex:1,overflow:"auto",padding:10,display:"flex",
            justifyContent:"center",alignItems:"flex-start",background:"#0a0b10"}}>
            <FacilityMap agentStatus={agSt} selRoom={selRoom} onRoomClick={setSelRoom} activeFlow={flow} onSpriteClick={setPersonaAgent}/>
          </div>

          {/* Bottom strip */}
          <div style={{flexShrink:0,padding:"0 10px 10px",display:"flex",flexDirection:"column",gap:6}}>
            {/* Web Preview */}
            {webPreview && (
              <div style={{background:"#12151d",border:"1px solid #22d3ee55",overflow:"hidden",position:"relative"}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"6px 12px",background:"#0f1218",borderBottom:"1px solid #252938"}}>
                  <span style={{color:"#22d3ee",fontSize:12,fontFamily:"'VT323',monospace",letterSpacing:1}}>🌐 WEB PREVIEW</span>
                  <div style={{display:"flex",gap:6}}>
                    <button onClick={()=>window.open(webPreview,'_blank')} style={{background:"rgba(34,211,238,0.1)",border:"1px solid #22d3ee44",color:"#22d3ee",padding:"2px 8px",fontFamily:"'VT323',monospace",fontSize:11,cursor:"pointer",letterSpacing:1}}>↗ OPEN</button>
                    <button onClick={()=>setWebPreview(null)} style={{background:"none",border:"1px solid #252938",color:"#94a3b8",padding:"2px 8px",fontFamily:"'VT323',monospace",fontSize:11,cursor:"pointer"}}>✕</button>
                  </div>
                </div>
                <iframe src={webPreview} style={{width:"100%",height:400,border:"none",background:"#fff"}} title="Web Preview" sandbox="allow-scripts"/>
              </div>
            )}
            {asset && (
              <div style={{background:"#12151d",border:"1px solid #252938",padding:"8px 12px",
                display:"flex",gap:12,alignItems:"center",fontFamily:"'VT323',monospace",flexWrap:"wrap"}}>
                <PixelCanvas grid={asset.pixels} size={60}/>
                <div>
                  <div style={{color:"#f5a623",fontSize:15}}>{asset.name}</div>
                  <div style={{color:"#94a3b8",fontSize:11}}>{asset.type?.toUpperCase()} · {asset.animationFrames}F</div>
                  <div style={{display:"flex",gap:3,marginTop:3}}>
                    {asset.palette?.map((c,i)=><div key={i} style={{width:10,height:10,background:c,border:"1px solid #252938"}}/>)}
                  </div>
                </div>
                {qcRep && <div style={{
                  background:qcRep.approved?"rgba(74,222,128,0.1)":"rgba(245,166,35,0.1)",
                  border:`1px solid ${qcRep.approved?"#4ade80":"#f5a623"}`,
                  padding:"4px 10px",color:qcRep.approved?"#4ade80":"#f5a623",fontSize:13}}>
                  {qcRep.approved?"✓ QC PASS":"⚠ QC FLAG"} · {qcRep.score}/100
                </div>}
              </div>
            )}
            <Log logs={gLogs} h={90}/>
          </div>
        </div>

        {selRoom && selCfg && (
          <Sidebar agentId={selRoom} status={agSt[selRoom]} progress={agPr[selRoom]}
            tasks={tasks[selRoom]||[]} logs={rLogs[selRoom]||[]}
            asset={asset} qcRep={qcRep}
            onClose={()=>{setSelRoom(null);setSidebarTab("status")}} onDownload={download} dlReady={dlReady}
            sidebarTab={sidebarTab} onTabChange={setSidebarTab}
            chatMessages={chatMessages[selRoom]||[]} onSendChat={sendChat}
            chatInput={chatInput} setChatInput={setChatInput} chatSending={chatSending}
            persona={personas[selRoom]} onOpenPersona={()=>setPersonaAgent(selRoom)}
          />
        )}
      </div>

      {/* Persona Editor Modal */}
      {personaAgent && (
        <PersonaEditor agentId={personaAgent} personas={personas}
          onSave={savePersona} onClose={()=>setPersonaAgent(null)}/>
      )}

      <div style={{borderTop:"1px solid #252938",padding:"4px 16px",
        display:"flex",justifyContent:"space-between",
        color:"#475569",fontSize:11,background:"#191d28",
        fontFamily:"'VT323',monospace",flexShrink:0}}>
        <span>HERMES OS v5 · PIXEL FACTORY · {isLive ? "⚡ KANBAN LIVE" : "📡 DIRECT MODE"}</span>
        <span>✦ POPO ONLINE · {prodCnt} PRODUCTIONS COMPLETE</span>
      </div>
    </div>
  );
}
